code = """import json
import pandas as pd
import re

# Load data
with open(locals()['var_function-call-8471687202024638385'], 'r') as f:
    tracks = pd.DataFrame(json.load(f))
with open(locals()['var_function-call-8471687202024637006'], 'r') as f:
    sales = pd.DataFrame(json.load(f))

sales['total_revenue'] = pd.to_numeric(sales['total_revenue'])
df = pd.merge(tracks, sales, on='track_id')

def extract_artist_title(row):
    title = row['title']
    artist = row['artist']
    if artist in [None, 'None', '[unknown]', '']:
        artist = None
    if title is None:
        title = ""
    if artist is None:
        if " - " in title:
            parts = title.split(" - ", 1)
            return parts[0].strip(), parts[1].strip()
        else:
            return "unknown", title.strip()
    else:
        return artist, title

df[['clean_artist', 'clean_title_raw']] = df.apply(lambda x: pd.Series(extract_artist_title(x)), axis=1)
df['norm_artist'] = df['clean_artist'].str.lower().str.strip()

def normalize_title(t):
    t = t.lower()
    t = re.sub(r'^\d+[-.\s]+', '', t)
    t = re.sub(r'\(.*?\)', '', t)
    t = re.sub(r'\[.*?\]', '', t)
    t = re.sub(r'\bfeat\..*', '', t)
    t = re.sub(r'[^\w\s]', '', t)
    return t.strip()

df['norm_title'] = df['clean_title_raw'].apply(normalize_title)

# Get top artists
artist_rev = df.groupby('norm_artist')['total_revenue'].sum().reset_index().sort_values('total_revenue', ascending=False)
top_artists_list = artist_rev.head(20)['norm_artist'].tolist()

results = {}
for artist in top_artists_list:
    if artist in ['unknown', '']: continue
    
    artist_df = df[df['norm_artist'] == artist]
    # Group by norm_title
    top_song = artist_df.groupby('norm_title')['total_revenue'].sum().reset_index().sort_values('total_revenue', ascending=False).head(1)
    if not top_song.empty:
        results[artist] = {
            "title": top_song['norm_title'].values[0],
            "revenue": top_song['total_revenue'].values[0]
        }

print("__RESULT__:")
print(json.dumps(results))"""

